import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { getSession } from "@/lib/session";
import { successResponse, errorResponse } from "@/lib/api-response";

// GET /api/hospitals/doctors - List all doctors for the logged-in hospital
export async function GET(request: Request) {
  try {
    const session = await getSession();

    if (!session || session.role !== "HOSPITAL") {
      return errorResponse("Unauthorized", 401);
    }

    const hospital = await prisma.hospital.findUnique({
      where: { userId: session.userId },
    });

    if (!hospital) {
      return errorResponse("Hospital profile not found", 404);
    }

    const doctors = await prisma.doctor.findMany({
      where: { hospitalId: hospital.id },
      orderBy: { createdAt: "desc" },
    });

    return successResponse({ doctors });
  } catch (error: any) {
    console.error("GET /api/hospitals/doctors error:", error);
    return errorResponse("Failed to fetch doctors", 500);
  }
}

// POST /api/hospitals/doctors - Add a new doctor
export async function POST(request: Request) {
  try {
    const session = await getSession();

    if (!session || session.role !== "HOSPITAL") {
      return errorResponse("Unauthorized", 401);
    }

    const hospital = await prisma.hospital.findUnique({
      where: { userId: session.userId },
    });

    if (!hospital) {
      return errorResponse("Hospital profile not found", 404);
    }

    const body = await request.json();
    const { name, email, phone, specialization, qualification, experience, consultationFee, bio } = body;

    const doctor = await prisma.doctor.create({
      data: {
        hospitalId: hospital.id,
        name,
        email,
        phone,
        specialization,
        qualification,
        experience: Number(experience),
        consultationFee: Number(consultationFee),
        bio,
      },
    });

    return successResponse({ doctor });
  } catch (error: any) {
    console.error("POST /api/hospitals/doctors error:", error);
    return errorResponse("Failed to add doctor", 500);
  }
}

// PUT /api/hospitals/doctors - Edit a doctor
export async function PUT(request: Request) {
  try {
    const session = await getSession();

    if (!session || session.role !== "HOSPITAL") {
      return errorResponse("Unauthorized", 401);
    }

    const hospital = await prisma.hospital.findUnique({
      where: { userId: session.userId },
    });

    if (!hospital) {
      return errorResponse("Hospital profile not found", 404);
    }

    const body = await request.json();
    const { id, name, email, phone, specialization, qualification, experience, consultationFee, bio, isAvailable } = body;

    // Verify doctor belongs to this hospital
    const existingDoctor = await prisma.doctor.findFirst({
      where: { id, hospitalId: hospital.id },
    });

    if (!existingDoctor) {
      return errorResponse("Doctor not found or unauthorized", 404);
    }

    const doctor = await prisma.doctor.update({
      where: { id },
      data: {
        name,
        email,
        phone,
        specialization,
        qualification,
        experience: Number(experience),
        consultationFee: Number(consultationFee),
        bio,
        isAvailable,
      },
    });

    return successResponse({ doctor });
  } catch (error: any) {
    console.error("PUT /api/hospitals/doctors error:", error);
    return errorResponse("Failed to update doctor", 500);
  }
}

// DELETE /api/hospitals/doctors - Delete a doctor
export async function DELETE(request: Request) {
  try {
    const session = await getSession();

    if (!session || session.role !== "HOSPITAL") {
      return errorResponse("Unauthorized", 401);
    }

    const hospital = await prisma.hospital.findUnique({
      where: { userId: session.userId },
    });

    if (!hospital) {
      return errorResponse("Hospital not found", 404);
    }

    const { searchParams } = new URL(request.url);
    const id = searchParams.get("id");

    if (!id) {
      return errorResponse("Doctor ID is required", 400);
    }

    // Verify doctor belongs to this hospital
    const existingDoctor = await prisma.doctor.findFirst({
      where: { id, hospitalId: hospital.id },
    });

    if (!existingDoctor) {
      return errorResponse("Doctor not found or unauthorized", 404);
    }

    await prisma.doctor.delete({
      where: { id },
    });

    return successResponse({ message: "Doctor deleted successfully" });
  } catch (error: any) {
    console.error("DELETE /api/hospitals/doctors error:", error);
    return errorResponse("Failed to delete doctor", 500);
  }
}
